#include <iostream>
using namespace std;

template<typename T>
class Stack {
    T data[100];
    int top;
public:
    Stack() : top(-1) {}
    void push(T x) { data[++top] = x; }
    T pop() { return data[top--]; }
};

int main() {
    Stack<int> s;
    s.push(10);
    s.push(20);
    cout << s.pop();
    return 0;
}

